import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface FeaturedDish {
  name: string;
  price: number;
  rating: number;
  reviews: number;
}

interface FeaturedDishesData {
  featuredDishes: FeaturedDish[];
}

export default function Widget() {
  const { featuredDishes } = response.data as FeaturedDishesData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#333' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: '#FFC107' }}>
            Featured Dishes
          </Typography>
          <Stack spacing={1}>
            {featuredDishes.map((dish) => (
              <Box key={dish.name} sx={{ bgcolor: '#424242', p: 1.5, borderRadius: 1 }}>
                <Typography variant="body1" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
                  {dish.name}
                </Typography>
                <Typography variant="body2" sx={{ color: '#FF5722' }}>
                  ${dish.price.toFixed(2)}
                </Typography>
                <Stack direction="row" spacing={0.5} alignItems="center">
                  <Typography variant="body2" sx={{ color: '#FFC107' }}>
                    {dish.rating.toFixed(1)}
                  </Typography>
                  <Typography variant="body2" sx={{ color: '#BDBDBD' }}>
                    ({dish.reviews} reviews)
                  </Typography>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
